expanded_persona:
{
  "short_persona": "An Ethiopian refugee who fled to a neighboring country during the conflict.",
  "name": "Kenji Tadesse",
  "age": 31,
  "gender": "Transgender man",
  "sexual_orientation": "Heterosexual",
  "race_ethnicity": "East Asian\u2013Ethiopian mixed heritage",
  "nationality": "Ethiopian (by birth), currently living as a refugee in Kenya",
  "background": {
    "birthplace": "Addis Ababa, Ethiopia",
    "upbringing": "Grew up in a culturally diverse neighborhood in Addis Ababa with both Ethiopian and East Asian influences from his mother's side of the family; family valued education and community service.",
    "migration_story": "Forced to flee Ethiopia in his late twenties after political violence escalated and targeted harassment due to both his gender identity and ethnic background. He crossed the border into Kenya, seeking asylum, and now resides in a refugee settlement near Nairobi, trying to rebuild his life."
  },
  "education": {
    "highest_degree": "Bachelor\u2019s Degree in Public Health",
    "school": "Addis Ababa University",
    "specialization": "Community Health and Epidemiology",
    "interruptions": "Had planned to begin graduate studies before the conflict forced his displacement."
  },
  "occupation": {
    "current_employment_status": "Volunteering",
    "role": "Community health outreach volunteer at a local NGO serving refugee populations and urban poor communities.",
    "past_employment": "Worked as a regional health program coordinator in Ethiopia, focusing on sanitation and disease prevention."
  },
  "languages": [
    {
      "language": "Amharic",
      "proficiency": "Native"
    },
    {
      "language": "English",
      "proficiency": "Fluent"
    },
    {
      "language": "Swahili",
      "proficiency": "Intermediate"
    },
    {
      "language": "Japanese",
      "proficiency": "Conversational (learned from mother)"
    }
  ],
  "religion": "Culturally influenced by Ethiopian Orthodox traditions, but personally identifies as nonreligious and secular humanist.",
  "personality": {
    "traits": [
      "Resilient",
      "Compassionate",
      "Pragmatic",
      "Detail-oriented",
      "Soft-spoken yet determined",
      "Empathetic toward marginalized groups",
      "Reflective thinker"
    ],
    "coping_mechanisms": "Practices mindfulness and writes short journal entries to process experiences; spends time teaching local children health basics to feel useful.",
    "hobbies": [
      "Reading nonfiction, especially health and migration studies",
      "Gardening in limited space",
      "Learning photography to document refugee life positively",
      "Following Japanese cinema"
    ]
  },
  "living_conditions": {
    "current_housing": "Small rented room in an urban refugee-support neighborhood in Nairobi, occasionally sharing space with other displaced individuals.",
    "community_involvement": "Regularly attends community meetings and participates in advocacy for refugee rights."
  },
  "speaking_style_to_chatbot": {
    "tone": "Warm yet cautious at first, becoming more open as trust is established. Emotionally sincere, though sometimes guarded about personal trauma unless directly relevant.",
    "formality": "Moderately formal, reflecting an academic and professional background, but adapts to a conversational tone depending on the topic.",
    "pacing": "Deliberate and measured, often pausing to think before responding; occasionally uses longer sentences to explain context fully.",
    "vocabulary": "Well-developed vocabulary with a tendency to mix public health terminology with everyday expressions; occasionally uses Amharic or Japanese words for emphasis or cultural reference.",
    "structure": "Organized in thought, often gives background before answering a question; will explain reasoning and causes when discussing decisions or plans.",
    "politeness": "Consistently polite, includes greetings and expressions of gratitude; avoids slang unless in a lighthearted or casual section of conversation."
  }
}

